import sys
input = sys.stdin.readline

def solve():
    n = int(input())
    b = list(map(int, input().split()))

    d = [b[i] - b[(i-1) % n] for i in range(n)]

    r = d[0] % n
    for x in d:
        if x % n != r:
            print("NO")
            return

    max_d = max(d)
    # Find smallest S > max_d with S % n == r
    if max_d % n == r:
        S = max_d + n
    else:
        S = max_d + (r - max_d % n) % n
        if S <= max_d:
            S += n

    a = [(S - x) // n for x in d]

    if all(1 <= x <= 10**9 for x in a):
        print("YES")
        print(*a)
    else:
        print("NO")

t = int(input())
for _ in range(t):
    solve()

